use wmill::Windmill;
use serde_json::json;
let wm = Windmill::default()?;
// For a variable containing JSON: {"key": "value"}
let json_var = wm.get_variable("u/admin/config")?;
// For a variable containing plain text
let text_var = wm.get_variable("u/user/plaintext_note")?;
